// Footnote popovers. Intercepts clicks on `a.footnote-ref` (the small
// superscript number generated by goldmark for [^N] markdown) and shows
// the footnote body in a positioned popover instead of scrolling to the
// bottom of the article. The canonical `<div class="footnotes">` block
// at the end of the article is left as the no-JS fallback.
//
// Click trigger → open near the anchor. Click trigger again → close.
// Click outside / Esc → close. Single shared popover element reused.
(function () {
  var popover = null;
  var activeTrigger = null;

  function ensurePopover() {
    if (popover) return popover;
    popover = document.createElement('div');
    popover.className = 'fn-popover';
    popover.setAttribute('role', 'tooltip');
    popover.hidden = true;
    document.body.appendChild(popover);
    return popover;
  }

  function position(el, anchor) {
    var rect = anchor.getBoundingClientRect();
    var margin = 8;
    var prevVisibility = el.style.visibility;
    el.style.visibility = 'hidden';
    el.hidden = false;
    var popW = el.offsetWidth;
    var popH = el.offsetHeight;
    var scrollY = window.scrollY;
    var scrollX = window.scrollX;
    var viewportW = document.documentElement.clientWidth;
    var viewportH = window.innerHeight;

    // Default: below the trigger, centered on it horizontally.
    var top = rect.bottom + scrollY + margin;
    var left = rect.left + scrollX + rect.width / 2 - popW / 2;

    // Flip above if it would overflow the bottom of the viewport.
    if (rect.bottom + popH + margin > viewportH && rect.top - popH - margin > 0) {
      top = rect.top + scrollY - popH - margin;
    }

    // Constrain horizontally inside the viewport.
    var minLeft = scrollX + margin;
    var maxLeft = scrollX + viewportW - popW - margin;
    if (left < minLeft) left = minLeft;
    if (left > maxLeft) left = Math.max(minLeft, maxLeft);

    el.style.top = top + 'px';
    el.style.left = left + 'px';
    el.style.visibility = prevVisibility;
  }

  function close() {
    if (!popover || popover.hidden) return;
    popover.hidden = true;
    if (activeTrigger) activeTrigger.setAttribute('aria-expanded', 'false');
    activeTrigger = null;
  }

  function open(trigger) {
    var href = trigger.getAttribute('href');
    if (!href || href.charAt(0) !== '#') return;
    var target = document.getElementById(decodeURIComponent(href.slice(1)));
    if (!target) return;

    ensurePopover();

    // Clone the footnote body, drop the backref arrow — it lands back on
    // the same anchor we just clicked, useless inside the popover.
    var clone = target.cloneNode(true);
    clone.querySelectorAll('.footnote-backref').forEach(function (n) { n.remove(); });
    popover.innerHTML = '';
    while (clone.firstChild) popover.appendChild(clone.firstChild);

    activeTrigger = trigger;
    trigger.setAttribute('aria-expanded', 'true');
    position(popover, trigger);
  }

  document.addEventListener('click', function (e) {
    var trigger = e.target.closest('a.footnote-ref');
    if (trigger) {
      e.preventDefault();
      if (activeTrigger === trigger) {
        close();
      } else {
        if (activeTrigger) close();
        open(trigger);
      }
      return;
    }
    // Click outside the popover (and not on a trigger) closes it.
    if (popover && !popover.hidden && !e.target.closest('.fn-popover')) {
      close();
    }
  });

  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape' && popover && !popover.hidden) {
      close();
      if (activeTrigger) activeTrigger.focus();
    }
  });

  window.addEventListener('scroll', function () {
    if (popover && !popover.hidden && activeTrigger) position(popover, activeTrigger);
  }, { passive: true });
  window.addEventListener('resize', function () {
    if (popover && !popover.hidden && activeTrigger) position(popover, activeTrigger);
  }, { passive: true });
})();
